const leads = $input.all();

if (leads.length === 0) {
  return [{ json: { hasLeads: false, csv: '', html: '', leadCount: 0 } }];
}

// Build CSV
const headers = ['Full Name', 'Phone', 'Email', 'Contacted', 'Replied', 'Status', 'Temperature', 'Date Added'];
const rows = leads.map(l => {
  const d = l.json;
  return [
    d.full_name || '',
    d.phone || '',
    d.email || '',
    d.last_contacted_at ? 'Yes' : 'No',
    d.last_replied_at ? 'Yes' : 'No',
    (d.status || '').replace('_', ' '),
    d.temperature || '',
    d.created_at ? new Date(d.created_at).toLocaleDateString('en-US') : ''
  ];
});

// Sanitize CSV injection: prefix cells starting with =, +, -, @ with a single quote
function sanitize(v) { return /^[=+\-@\t\r]/.test(v) ? "'" + v : v; }

const csvLines = [headers.join(',')];
for (const row of rows) {
  csvLines.push(row.map(v => '"' + sanitize(v).replace(/"/g, '""') + '"').join(','));
}
const csv = csvLines.join('\n');

// Build HTML summary
const newLeads = leads.filter(l => !l.json.last_contacted_at).length;
const contacted = leads.filter(l => l.json.last_contacted_at && !l.json.last_replied_at).length;
const replied = leads.filter(l => l.json.last_replied_at).length;

let html = '<h2>Weekly Lead Report — Freedom Ryder</h2>';
html += '<p><strong>Date:</strong> ' + new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' }) + '</p>';
html += '<hr>';
html += '<p><strong>Total leads assigned to you:</strong> ' + leads.length + '</p>';
html += '<ul>';
html += '<li>New / uncontacted: ' + newLeads + '</li>';
html += '<li>Contacted, awaiting reply: ' + contacted + '</li>';
html += '<li>Replied: ' + replied + '</li>';
html += '</ul>';
html += '<hr>';
html += '<p>Your full lead list is attached as a CSV. Reply to this email with any updates and Forrest will update the system.</p>';
html += '<p>Thanks, Bob!<br>— Freedom Ryder CRM</p>';

// Create CSV binary attachment
const today = new Date().toISOString().split('T')[0];
const fileName = 'bobs-leads-' + today + '.csv';
const binaryData = Buffer.from(csv, 'utf-8');

return [{
  json: { hasLeads: true, csv, html, leadCount: leads.length, fileName },
  binary: {
    attachment: {
      data: binaryData.toString('base64'),
      mimeType: 'text/csv',
      fileName: fileName
    }
  }
}];
